// Payload: tenant_id, conversation_id, contact_phone, contact_name, messages[], assigned_to_id, department_id, closed_at
const raw = $input.first().json;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const messages = Array.isArray(body.messages) ? body.messages : [];
const text = messages
  .map(m => `${m.sender_name || m.direction || '?'}: ${(m.content || '').trim()}`)
  .filter(Boolean)
  .join('\n\n');
const model = (body.model && String(body.model).trim()) || 'qwen3:14b';
const prompt = `Você é um assistente de análise de atendimento. Analise as mensagens abaixo e responda SOMENTE com um objeto JSON válido, sem texto adicional, sem markdown, sem explicações.

Formato exato:
{
  "subject": "<assunto principal em uma frase curta>",
  "sentiment": "<positivo | neutro | negativo>",
  "satisfaction": <número inteiro de 1 a 5>,
  "confidence": <número decimal entre 0 e 1 indicando sua confiança na análise>,
  "summary": "<resumo conciso da conversa em 2-4 frases>"
}

Mensagens:\n${text || '(vazio)'}`;
return [{ json: { prompt, model } }];

// Resposta do LLM: extrair summary, subject, sentiment, satisfaction, confidence via JSON
const item = $input.first().json;
const rawText = (item.response || item.message?.content || '').trim();

let parsed = null;

// 1. Tenta JSON.parse direto
try {
  parsed = JSON.parse(rawText);
} catch (_) {
  // 2. Tenta extrair bloco JSON com regex
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) {
    try { parsed = JSON.parse(match[0]); } catch (_) {}
  }
}

// 3. Normaliza campos
const summary = (parsed?.summary || rawText || '').trim();
const subject = (parsed?.subject || '').trim();

const rawSentiment = String(parsed?.sentiment || '').toLowerCase().trim();
const sentiment = ['positivo', 'neutro', 'negativo'].includes(rawSentiment) ? rawSentiment : '';

const rawSatisfaction = parsed?.satisfaction;
const satisfactionNum = parseInt(rawSatisfaction, 10);
const satisfaction = (!isNaN(satisfactionNum) && satisfactionNum >= 1 && satisfactionNum <= 5) ? satisfactionNum : null;

const rawConfidence = parsed?.confidence;
const confidenceNum = parseFloat(rawConfidence);
const confidence = (!isNaN(confidenceNum) && confidenceNum >= 0 && confidenceNum <= 1) ? confidenceNum : null;

return [{ json: { summary, subject, sentiment, satisfaction, confidence } }];
